Crie uma arquitetura escalável.

Para criar um sistema de inventário escalável na Unity utilizando C#, você pode seguir a seguinte estrutura:

### 1. Estrutura de Pastas

```
Assets/
├── Scripts/
│   ├── InventorySystem/
│   │   ├── Item.cs
│   │   ├── ItemData.cs
│   │   ├── Inventory.cs
│   │   ├── InventoryManager.cs
│   │   ├── InventoryEvent.cs
│   │   └── SaveLoadInventory.cs
│   └── ...
├── Resources/
│   ├── Items/
│   │   ├── ItemPrefab1.prefab
│   │   ├── ItemPrefab2.prefab
│   │   └── ...
│   └── ...
└── ...
```

### 2. Criando os Componentes necessários

#### `Item.cs` - Classe base para todos os itens

```csharp
using UnityEngine;

[CreateAssetMenu(fileName = "NewItem", menuName = "Items/Item")]
public class Item : ScriptableObject
{
    public string itemName;
    public Sprite icon;
    public int stackSize = 1;
}
```

#### `ItemData.cs` - Dados específicos de cada item (se necessário)

```csharp
using System.Collections.Generic;
using UnityEngine;

[System.Serializable]
public class ItemData
{
    public Item item;
    public int amount;
}
```

#### `Inventory.cs` - Representa o inventário do jogador

```csharp
using System.Collections.Generic;
using UnityEngine;

public class Inventory : MonoBehaviour
{
    private List<ItemData> items = new List<ItemData>();

    public bool AddItem(Item item, int amount)
    {
        foreach (var data in items)
        {
            if (data.item == item)
            {
                data.amount += Mathf.Min(amount, item.stackSize - data.amount);
                return true;
            }
        }

        if (amount > item.stackSize) return false;

        items.Add(new ItemData { item = item, amount = amount });
        return true;
    }

    public bool RemoveItem(Item item, int amount)
    {
        for (int i = 0; i < items.Count; i++)
        {
            if (items[i].item == item)
            {
                if (items[i].amount >= amount)
                {
                    items[i].amount -= amount;
                    if (items[i].amount <= 0)
                        items.RemoveAt(i);

                    return true;
