    private Dictionary<string, object> states = new Dictionary<string, object>();

    public T GetState<T>(string key) where T : class
    {
        if (states.ContainsKey(key))
        {
            return states[key] as T;
        }
        return null;
    }

    public void AddState(string key, object state)
    {
        states[key] = state;
    }

    public void RemoveState(string key)
    {
        states.Remove(key);
    }
}
